import React, { useState, useEffect } from 'react';
import { Card, Table, Badge, Button, Spinner } from 'react-bootstrap';
import axios from 'axios';

function OrdersList() {
  const [orders, setOrders] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  const token = localStorage.getItem('token');

  useEffect(() => {
    loadOrders();
  }, []);

  const loadOrders = async () => {
    try {
      const response = await axios.get('http://localhost:5051/api/Orders', {
        headers: { Authorization: `Bearer ${token}` }
      });
      setOrders(response.data);
    } catch (err) {
      setError('Ошибка загрузки заказов');
    }
    setLoading(false);
  };

  // 👇 ВОТ СЮДА ВСТАВЛЯЕТЕ ФУНКЦИЮ ПЕЧАТИ (после loadOrders)
  const printOrder = async (orderId) => {
    try {
      const response = await axios.get(`http://localhost:5051/api/Orders/${orderId}`, {
        headers: { Authorization: `Bearer ${token}` }
      });
      
      const order = response.data;
      const printWindow = window.open('', '_blank');
      
      printWindow.document.write(`
        <html>
          <head>
            <title>Заказ ${order.orderNumber}</title>
            <style>
              body { font-family: Arial; padding: 20px; }
              table { width: 100%; border-collapse: collapse; margin: 20px 0; }
              th, td { border: 1px solid #ddd; padding: 8px; text-align: left; }
              th { background: #f5f5f5; }
              .header { text-align: center; margin-bottom: 20px; }
              .total { font-size: 1.2em; font-weight: bold; text-align: right; }
            </style>
          </head>
          <body>
            <div class="header">
              <h1>🚗 AutoParts Shop</h1>
              <h2>Заказ №${order.orderNumber}</h2>
              <p>Дата: ${new Date(order.orderDate).toLocaleDateString('ru-RU')}</p>
            </div>
            
            <div>
              <strong>Клиент:</strong> ${order.customer.fullName}<br>
              <strong>Телефон:</strong> ${order.customer.phone}<br>
              <strong>Авто:</strong> ${order.customer.carModel || 'Не указано'}
            </div>
            
            <table>
              <thead>
                <tr>
                  <th>Артикул</th>
                  <th>Наименование</th>
                  <th>Бренд</th>
                  <th>Кол-во</th>
                  <th>Цена</th>
                  <th>Сумма</th>
                </tr>
              </thead>
              <tbody>
                ${order.items.map(item => `
                  <tr>
                    <td>${item.partArticle}</td>
                    <td>${item.partName}</td>
                    <td>${item.partBrand || '-'}</td>
                    <td>${item.quantity}</td>
                    <td>${item.priceAtOrder.toFixed(2)} ₽</td>
                    <td>${item.total.toFixed(2)} ₽</td>
                  </tr>
                `).join('')}
              </tbody>
            </table>
            
            <div class="total">
              Итого: ${order.totalAmount.toFixed(2)} ₽
            </div>
          </body>
        </html>
      `);
      
      printWindow.document.close();
      printWindow.print();
    } catch (err) {
      alert('Ошибка загрузки заказа');
    }
  };

  const getStatusBadge = (status) => {
    switch (status) {
      case 'New': return <Badge bg="primary">Новый</Badge>;
      case 'Paid': return <Badge bg="success">Оплачен</Badge>;
      case 'Shipped': return <Badge bg="info">Отгружен</Badge>;
      case 'Cancelled': return <Badge bg="danger">Отменен</Badge>;
      default: return <Badge bg="secondary">{status}</Badge>;
    }
  };

  if (loading) return <div className="text-center mt-5"><Spinner /> Загрузка...</div>;
  if (error) return <div className="alert alert-danger">{error}</div>;

  return (
    <div>
      <h2 className="mb-4">📋 Заказы</h2>
      
      <Card>
        <Card.Body>
          <Table striped hover responsive>
            <thead>
              <tr>
                <th>Номер заказа</th>
                <th>Клиент</th>
                <th>Дата</th>
                <th>Сумма</th>
                <th>Позиций</th>
                <th>Статус</th>
                <th>Действия</th>   {/* 👈 ДОБАВИЛИ КОЛОНКУ */}
              </tr>
            </thead>
            <tbody>
              {orders.map(order => (
                <tr key={order.id}>
                  <td><strong>{order.orderNumber}</strong></td>
                  <td>{order.customerName}</td>
                  <td>{new Date(order.orderDate).toLocaleDateString('ru-RU')}</td>
                  <td>{order.totalAmount.toFixed(2)} ₽</td>
                  <td>{order.itemsCount}</td>
                  <td>{getStatusBadge(order.status)}</td>
                  <td>   {/* 👈 ДОБАВИЛИ КНОПКУ */}
                    <Button 
                      variant="outline-secondary" 
                      size="sm" 
                      onClick={() => printOrder(order.id)}
                    >
                      🖨
                    </Button>
                  </td>
                </tr>
              ))}
            </tbody>
          </Table>
          
          {orders.length === 0 && (
            <div className="text-center text-muted py-4">
              Заказов пока нет
            </div>
          )}
        </Card.Body>
      </Card>
    </div>
  );
}

export default OrdersList;
